#include<bits/stdc++.h>
using namespace std;
vector <int> a[100001];
bool b[100001];
bool c[100001];
queue<int> q;
int n, maxd, m;
void dfs(int x) {
	cout << x << " ";
	for (int i = 0; i < a[x].size(); i++) {
		if (!b[a[x][i]]) {
			b[a[x][i]] = 1;
			dfs(a[x][i]);
		}
	}
}
void bfs() {
	q.push(1);
	c[1] = 1;
	while (!q.empty()) {
		cout << q.front() << ' ';
		for (int i = 0; i < a[ q.front()].size(); i++) {
			if (!c[a[ q.front()][i]]) {
				q.push(a[q.front()][i]);
				c[a[ q.front()][i]] = 1;
			}
		}
		q.pop();
	}
}
int main() {
	ios::sync_with_stdio(false);
	cin.tie(0);
	cout.tie(0);
	cin >> n >> m;
	for (int i = 1; i <= m; i++) {
		int x, y;
		cin >> x >> y;
		a[x].push_back(y);
	}
	for (int i = 1; i <= n; i++) {
		sort(a[i].begin(), a[i].end());
	}
	b[1] = 1;
	dfs(1);
	cout << '\n';
	bfs();
	return 0;
}
